SELECT B.PJT_SN, B.PJT_NM, B.PJT_STTS_CD, B.employeeId, B.FRST_REG_DT, B.LAST_MDFCN_DT, B.PJT_BGNG_DT, B.PJT_END_DT, B.TB_PJT_APR FROM TB_PJT_BASC B WHERE (B.USE_YN IS NULL OR B.USE_YN = 'Y')
AND (B.PJT_NM LIKE CONCAT('%', #{keyword}, '%') OR B.employeeId LIKE CONCAT('%', #{keyword}, '%'))
AND B.employeeId = #{employeeId}
AND B.TB_PJT_APR = #{employeeId}
ORDER BY B.LAST_MDFCN_DT DESC, B.PJT_SN DESC LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(1) FROM TB_PJT_BASC B WHERE (B.USE_YN IS NULL OR B.USE_YN = 'Y')
AND (B.PJT_NM LIKE CONCAT('%', #{keyword}, '%') OR B.employeeId LIKE CONCAT('%', #{keyword}, '%'))
AND B.employeeId = #{employeeId}
AND B.TB_PJT_APR = #{employeeId}

/* com.kdt.pjt_pjt.mapper.pjt_mng.PjtMngMapper  */
  SELECT COUNT(*)
  FROM TB_PJT_BASC
  WHERE (USE_YN IS NULL OR USE_YN = 'Y')
    AND employeeId = #{employeeId}
